  1	import { type Dispatch, type FC, type SetStateAction, useEffect } from 'react';
  2	
  3	import { Divider, Form, Text, TextVariants } from '@patternfly/react-core';
  4	import { isEmpty } from '@utils/helpers';
  5	import { useForkliftTranslation } from '@utils/i18n';
  6	
  7	import { isTermsInvalid } from './utils/isTermsInvalid';
  8	import {
  9	  AffinityCondition,
 10	  type AffinityRowData,
 11	  AffinityType,
 12	  type useIDEntitiesValue,
 13	} from './utils/types';
 14	import AffinityConditionSelect from './AffinityConditionSelect';
 15	import AffinityTypeSelect from './AffinityTypeSelect';
 16	import ExpressionEditList from './ExpressionEditList';
 17	import FieldsEditList from './FieldsEditList';
 18	import NodeExpressionDescriptionText from './NodeExpressionDescriptionText';
 19	import NodeFieldsDescriptionText from './NodeFieldsDescriptionText';
 20	import PreferredAffinityWeightInput from './PreferredAffinityWeightInput';
 21	import TopologyKeyInput from './TopologyKeyInput';
 22	import WorkloadExpressionDescriptionText from './WorkloadExpressionDescriptionText';
 23	
 24	type AffinityFormProps = {
 25	  expressions: useIDEntitiesValue;
 26	  fields: useIDEntitiesValue;
 27	  focusedAffinity: AffinityRowData;
 28	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
 29	  setSubmitDisabled: Dispatch<SetStateAction<boolean>>;
 30	};
 31	
 32	const AffinityForm: FC<AffinityFormProps> = ({
 33	  expressions,
 34	  fields,
 35	  focusedAffinity,
 36	  setFocusedAffinity,
 37	  setSubmitDisabled,
 38	}) => {
 39	  const { t } = useForkliftTranslation();
 40	
 41	  const isNodeAffinity = focusedAffinity?.type === AffinityType.node;
 42	
 43	  useEffect(() => {
 44	    setSubmitDisabled(
 45	      (isEmpty(expressions?.entities) && isEmpty(fields?.entities)) ||
 46	        isTermsInvalid(expressions?.entities) ||
 47	        isTermsInvalid(fields?.entities),
 48	    );
 49	  }, [expressions, fields, setSubmitDisabled]);
 50	
 51	  return (
 52	    <Form>
 53	      <Text className="text-muted" component={TextVariants.p}>
 54	        {t(
 55	          'Define an affinity rule. This rule will be added to the list of affinity rules applied to this workload.',
 56	        )}
 57	      </Text>
 58	      <AffinityTypeSelect
 59	        focusedAffinity={focusedAffinity}
 60	        setFocusedAffinity={setFocusedAffinity}
 61	      />
 62	      <AffinityConditionSelect
 63	        focusedAffinity={focusedAffinity}
 64	        setFocusedAffinity={setFocusedAffinity}
 65	      />
 66	      {focusedAffinity?.condition === AffinityCondition.preferred && (
 67	        <PreferredAffinityWeightInput
 68	          focusedAffinity={focusedAffinity}
 69	          setFocusedAffinity={setFocusedAffinity}
 70	          setSubmitDisabled={setSubmitDisabled}
 71	        />
 72	      )}
 73	      {!isNodeAffinity && (
 74	        <TopologyKeyInput
 75	          focusedAffinity={focusedAffinity}
 76	          setFocusedAffinity={setFocusedAffinity}
 77	          setSubmitDisabled={setSubmitDisabled}
 78	        />
 79	      )}
 80	      <Divider />
 81	      <ExpressionEditList
 82	        errorHelperText={t('Missing fields in {{kind}} labels', {
 83	          kind: isNodeAffinity ? 'node' : 'workload',
 84	        })}
 85	        helperText={
 86	          isNodeAffinity ? <NodeExpressionDescriptionText /> : <WorkloadExpressionDescriptionText />
 87	        }
 88	        expressions={expressions}
 89	        label={isNodeAffinity ? t('Node labels') : t('Workload labels')}
 90	      />
 91	      {isNodeAffinity && (
 92	        <>
 93	          <Divider />
 94	          <FieldsEditList
 95	            errorHelperText={t('Missing fields in node fields')}
 96	            fields={fields}
 97	            helperText={<NodeFieldsDescriptionText />}
 98	            label={t('Node fields')}
 99	          />
100	        </>
101	      )}{' '}
102	    </Form>
103	  );
104	};
105	export default AffinityForm;

